"""
mkt-context | 2 Samuel 22-23
Run: python3 scripts/zc-context-2samuel-22-23.py

Ch 22 (= Psalm 18): royal thanksgiving hymn; theophanic storm imagery; divine warrior motif
Ch 23: David's last words (messianic poem); gibbôrîm warrior-band; Bethlehem water as libation
"""

import json
import pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}


def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')


def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


SAMUEL2_CONTEXT_CH22_23 = {
    "22": {
        "1": "<p>2 Samuel 22 is identical (with minor textual variants) to Psalm 18, which is titled 'A Psalm of David … on the day when YHWH delivered him from the hand of all his enemies and from the hand of Saul.' Its placement at the end of the Samuel narrative (alongside 23:1-7 and the appendices of chs 21-24) is deliberate: the editors frame David's story with its theological interpretive key. The song is a royal thanksgiving hymn (<em>tôdâ</em>) — the genre in which a king who has been delivered from mortal danger publicly testifies to YHWH's rescue in the presence of the community. In ANE courts, the king's public acknowledgment of divine rescue legitimized his rule by demonstrating that the deity had chosen and vindicated him.</p>",
        "2": "<p>The opening cluster of metaphors — 'my rock, my fortress, my deliverer, my God, my shield, the horn of my salvation, my stronghold, my refuge, my savior' — draws on geological and military vocabulary rooted in David's actual fugitive experience in the Judean wilderness. The limestone cliffs and caves of Adullam, En-gedi, Masada, and the Negev highlands are the experiential referent behind the rock/fortress/stronghold language. YHWH is not an abstraction but the one who acted in precisely those physical terrains. This is ANE theology at its most concrete: the deity's protection is expressed in the categories of what survival in the landscape actually required.</p>",
        "3": "<p>The piling of epithets for YHWH in v2-3 (seven distinct terms) is characteristic of the royal thanksgiving genre in the ancient Near East. Ugaritic hymns similarly accumulate divine epithets at the opening. But where Baal hymns emphasize the storm-god's power, David's poem centers on relational protection — YHWH is 'my' rock, 'my' fortress. The possessive pronouns are theologically significant: this is not generic divine power but covenantal belonging. The <em>hesed</em> framework (covenant loyalty) underlies every epithet.</p>",
        "4": "<p>'I call upon YHWH, who is worthy to be praised, and I am saved from my enemies.' The logic of petition and rescue is the spine of the entire poem: cry → YHWH hears → YHWH acts → rescue → public praise. This is the thanksgiving psalm structure that the Psalter systematizes. The psalm functions as public testimony in the covenant community — 'I was in danger, I called, YHWH delivered, let me tell you what he did' — which is the prototype of the NT gospel testimony structure.</p>",
        "5": "<p>The 'waves/breakers of death' and 'torrents of destruction' that surround the psalmist in vv5-6 use <em>ḥeḇlê māweṯ</em> (cords/waves of death) and <em>naḥălê ḇĕliyyaʿal</em> (torrents of worthlessness/destruction). <em>Bĕliyyaʿal</em> is the term for the underworld forces of chaos in Canaanite cosmology — later personified as Belial in Second Temple literature and the NT (2 Cor 6:15). The psalmist is not using mythology literally but drawing on the existing cosmological vocabulary to describe mortal danger at its most extreme: the forces that belong to the realm of death have surrounded him.</p>",
        "6": "<p>'The cords of Sheol entangled me; the snares of death confronted me.' <em>Sheʾôl</em> in OT cosmology is the shadowy underworld where the dead go — not yet the fully developed afterlife theology of intertestamental Judaism, but the realm of diminished existence, distance from YHWH, and the end of covenant relationship. David's language is hyperbolic and cultic: he was so close to death that Sheol's cords already had him. The deliverance YHWH works is a kind of resurrection from the realm of the dead — a theme Paul and the NT writers will apply to Christ's literal resurrection.</p>",
        "7": "<p>'In my distress I called upon YHWH; to my God I called. From his temple he heard my voice, and my cry came to his ears.' The paradox: YHWH dwells in his heavenly temple yet hears the cry of a fugitive in the Judean wilderness. The temple theology of Israel (and its precursors in the tent/tabernacle) centers on YHWH's accessibility: the sovereign of the cosmos attends to the voice of the endangered. This is the theological claim that distinguishes Israelite religion from ANE royal ideology, where the gods primarily attended to the king in ritual contexts, not to the desperate individual in the field.</p>",
        "8": "<p>The theophany of vv8-16 is one of the most elaborate in the Hebrew Bible, drawing directly on Canaanite storm-god imagery while thoroughly demythologizing it. In the Ugaritic Baal texts, Baal is the storm-deity who rides the clouds, hurls lightning bolts, and defeats the sea-chaos monster Yam. 2 Samuel 22 / Psalm 18 takes this same imagery — earthquake, smoke, consuming fire, dark clouds, hailstones, lightning — and attributes it entirely to YHWH's intervention on behalf of his servant. The cosmological battle is relocated: not Baal vs Yam, but YHWH responding to his covenant partner's cry. This is not naive mythology but conscious theological reuse of the available imagery.</p>",
        "9": "<p>'Smoke went up from his nostrils, and devouring fire from his mouth; glowing coals flamed forth from him.' The anthropomorphic language for YHWH's anger — fire and smoke from his nostrils — echoes Sinai (Exod 19:18: the mountain smoked because YHWH descended on it in fire) and the consuming-fire theophany tradition. In Canaanite mythology, the storm deity's weapon is fire. Here fire serves YHWH's covenantal protection of his servant. The imagery will be systematized in later prophetic judgment oracles where YHWH's fire consumes enemies of his people (Isa 66:15-16; Nah 1:6).</p>",
        "10": "<p>'He bowed the heavens and came down; thick darkness was under his feet.' The descent theophany — YHWH 'coming down' — is the standard OT formula for divine intervention in history (Gen 11:5; Exod 3:8; 19:11). The darkness under his feet combines the cloud imagery of Sinai (Exod 19:9: 'I will come to you in a thick cloud') with the royal imagery of the divine throne. In ANE palace iconography, the divine sovereign sits on clouds or is carried by cherubim. The poem democratizes this royal theophany: YHWH descends for a fugitive shepherd-king.</p>",
        "11": "<p>'He rode on a cherub and flew; he was seen on the wings of the wind.' The cherubim as YHWH's throne-chariot (cf. Ezek 1; 10) and the wings-of-wind imagery draw on the same Canaanite tradition of the storm deity riding the clouds (Baal's epithet in Ugaritic: <em>rkb ʿrpt</em>, 'rider of the clouds'). YHWH's exclusive claim to this title is asserted by Ps 68:4 and Deut 33:26. The combat/battle frame is important: YHWH rides out to war, and his war is on behalf of his servant. The divine warrior motif here is the background for Revelation 19's rider on the white horse.</p>",
        "12": "<p>'He made darkness around him his canopy, thick clouds, a gathering of water.' The darkness that surrounds YHWH in theophany is paradoxical — the God who is light (1 John 1:5; Ps 27:1) approaches in thick darkness. This darkness is not malevolent but revelatory concealment: YHWH's full glory cannot be directly witnessed (Exod 33:20-23). The cloud-and-darkness tradition goes back to Sinai and runs through the Tent of Meeting, the Temple (1 Kings 8:12: YHWH said he would dwell in thick darkness), and ultimately to the crucifixion darkness (Matt 27:45) — the final moment of God's veiled self-giving.</p>",
        "13": "<p>'Out of the brightness before him hailstones and coals of fire broke through the clouds.' The storm weapons — hail and lightning/fire — are YHWH's battle arsenal against his enemies. In the Exodus narrative, hail and fire are two of the ten plagues (Exod 9:23-24: fire ran down to the earth mixed with the hail). In the conquest period, YHWH throws down large hailstones on the Amorites (Josh 10:11). The poem assembles this tradition of divine war-weaponry to contextualize David's specific deliverances as part of YHWH's ongoing warfare on behalf of covenant Israel.</p>",
        "14": "<p>'YHWH thundered from heaven, and the Most High uttered his voice.' The thunder as divine speech is a motif shared across ANE cultures: Baal's voice is the thunder in Ugaritic poetry. Here YHWH's thunder-voice precedes his combat intervention. The voice of YHWH (<em>qôl YHWH</em>) is a theological theme throughout the Psalter (Ps 29: seven thunders of the divine voice) and culminates in the divine voice from heaven at Jesus's baptism and transfiguration — the Father's public identification of his Son at the beginning and climax of his ministry.</p>",
        "15": "<p>'And he sent out arrows and scattered them; lightning, and routed them.' YHWH's arrows are the lightning bolts — a standard ANE warrior-deity motif. The Ugaritic Baal wields lightning as his weapon against Mot (death) and the sea. Here the lightning routes David's enemies. The poem makes no distinction between the natural phenomenon (lightning in a storm) and divine agency — the storm itself is YHWH's active combat on behalf of his covenant partner. This integration of natural phenomenon and divine action is characteristic of OT theology: YHWH acts through creation, not apart from it.</p>",
        "16": "<p>'Then the channels of the sea were seen, and the foundations of the world were laid bare, at the rebuke of YHWH, at the blast of the breath of his nostrils.' The cosmic exposure of the sea-floor and earth's foundations echoes the Exodus sea-crossing (Exod 14:21-22: YHWH drove back the sea, and the waters were divided, and Israel walked on dry ground). The same cosmic-level theophany that opened a path for Israel at the Red Sea is invoked for David's personal deliverance. Individual and national salvation are on the same continuum — both are YHWH's sovereign intervention over the forces that threaten covenant life.</p>",
        "17": "<p>'He sent from on high, he took me; he drew me out of many waters.' The 'many waters' (<em>mayim rabbîm</em>) is the OT's standard image for overwhelming chaos and mortal danger (cf. Ps 29:3; 32:6; Isa 43:2). The verb 'drew me out' (<em>yimsĕʾēnî</em>) uses the same root as the name <em>Mōšeh</em> (Moses): 'he who was drawn out of the water.' David's rescue from the many waters recapitulates the Moses-from-the-Nile pattern — both are drawn-out-ones whom YHWH rescues from deadly waters for his redemptive purposes.</p>",
        "18": "<p>'He rescued me from my strong enemy, from those who hated me, for they were too mighty for me.' The theological claim is stark: David survived not because of superior military skill but because the enemy was stronger than David, and YHWH intervened. This is the anti-merit logic that runs through the whole poem: David's survival is entirely attributable to divine election and covenant faithfulness, not human prowess. The psalm's placement after the narrative of David's failures (Uriah, Absalom, census) makes this attribution more striking — the man who needed rescue because of his own sins was also the man YHWH inexplicably continued to deliver.</p>",
        "19": "<p>'They confronted me in the day of my calamity, but YHWH was my support.' The phrase 'day of calamity' (<em>yôm ʾêḏî</em>) is a standard expression for the moment of existential crisis. YHWH as 'support' (<em>mišʿān</em>) — a leaning-post, a staff — is an intimate domestic metaphor inserted into the theophanic cosmic battle frame. YHWH the storm-rider is also YHWH the staff one leans on. The oscillation between cosmic sovereignty and intimate personal support is characteristic of Israel's covenant theology.</p>",
        "20": "<p>'He brought me out into a broad place; he rescued me, because he delighted in me.' The 'broad place' (<em>merḥāḇ</em>) is the spatial metaphor for covenant security — the opposite of the <em>ṣar</em> (narrow/straits) of danger. YHWH delivers into spaciousness. But the rationale — 'because he delighted in me' (<em>yĕḥopĕṣ bî</em>) — is the covenant election language of grace: YHWH's delight in David precedes and grounds the rescue. It is not performance-based. Paul's 'he who did not spare his own Son' (Rom 8:32) is this same logic at its ultimate expression.</p>",
        "21": "<p>The righteousness claim of vv21-25 — 'YHWH dealt with me according to my righteousness; according to the cleanness of my hands he recompensed me' — has generated theological difficulty since it seems incompatible with David's actual record (Bathsheba, Uriah, Absalom's rebellion partly caused by David's failures). The key is the covenantal and forensic context: the psalm is a post-battle thanksgiving in which David claims that YHWH vindicated him against his enemies because he (David) remained covenant-faithful relative to those specific enemies — not that he was sinlessly perfect. The righteousness claim is relational and situational, not absolute.</p>",
        "22": "<p>'For I have kept the ways of YHWH and have not wickedly departed from my God.' The claim to have kept YHWH's ways stands in tension with 2 Sam 11-12 until we recognize the psalm's probable context: a thanksgiving for military deliverance, perhaps in the context of wars against Saul or the Philistines or foreign nations, not retrospective assessment of his whole life. Saul, by contrast, repeatedly departed from YHWH's explicit commands (1 Sam 15; 28). Relative to Saul as failed king, David's covenant faithfulness is genuine and is what the poem is asserting.</p>",
        "23": "<p>'For all his rules were before me, and his statutes I did not put away from me.' The claim to have kept YHWH's statutes before him echoes the Deuteronomic ideal of the king who keeps a copy of the Torah and reads it 'all the days of his life' (Deut 17:18-20). David is the embodiment — imperfectly — of this royal ideal. The contrast with the kings who multiplied horses, wives, and gold (Deut 17:16-17 = Solomon, explicitly violated) makes David's relative fidelity more visible in hindsight.</p>",
        "24": "<p>'I was blameless before him, and I kept myself from guilt.' <em>Tāmîm</em> (blameless) is the same word used of Job (1:1) and Noah (Gen 6:9). It does not mean sinless perfection but integrity and wholeness — living aligned with covenant relationship. YHWH's verdict on David 'a man after my own heart' (1 Sam 13:14; Acts 13:22) is the covenant-theology reading of tāmîm: David's fundamental orientation toward YHWH was aligned, even when specific acts were catastrophically wrong and required confession and restoration.</p>",
        "25": "<p>'Therefore YHWH has recompensed me according to my righteousness, according to my cleanness in his sight.' The lex talionis logic of covenant — faithfulness receives blessing, faithlessness receives curse (Deut 28) — is affirmed here but immediately balanced by the surrounding context of the poem, which emphasizes YHWH's grace and delight (v20) as the ground of deliverance. The righteousness-recompense claim is not a works-salvation claim but a covenant-law claim: YHWH is just, and his justice includes rewarding those who are in covenant with him.</p>",
        "26": "<p>'With the merciful you show yourself merciful; with the blameless man you show yourself blameless.' The divine-mirror principle (vv26-28) — YHWH reflects back the posture of the human heart — is one of the most searching theological statements in the Psalter. It is not that YHWH changes his character based on human behavior, but that the same divine action (YHWH's consistent holiness and covenant faithfulness) is experienced very differently depending on whether one approaches in covenant loyalty or in rebellion. The crooked experience YHWH's straightness as crooked because their own crookedness distorts their perception.</p>",
        "27": "<p>'With the pure you show yourself pure, and with the crooked you make yourself seem tortuous.' This divine-mirror principle is cited and applied in Proverbs (Prov 3:34: he mocks mockers but gives grace to the humble), quoted in Jas 4:6 and 1 Pet 5:5 as the frame for NT humility ethics. YHWH's humbling of the proud and lifting of the humble is not a mere principle — it is the structural shape of the cross: Christ humbles himself to the point of death, and therefore God exalts him to the highest place (Phil 2:8-9).</p>",
        "28": "<p>'For you save a humble people, but your eyes are on the haughty to bring them down.' The inversion theology of the poem — humble lifted, haughty brought down — is Hannah's prayer (2 Sam 2:1-10), Mary's Magnificat (Luke 1:46-55), and the Sermon on the Mount beatitudes ('the poor in spirit … shall inherit the earth') in embryonic form. The structure of the Davidic narrative — Israel's king as a shepherd rejected by the powerful, elevated by YHWH — is the structural template for the Gospel's king rejected and vindicated.</p>",
        "29": "<p>'For you are my lamp, O YHWH, and my God lightens my darkness.' The lamp metaphor shifts from cosmic theophany to intimate personal provision. The lamp in Israelite domestic life is the guarantee of not stumbling in darkness — the most basic form of guidance and safety. YHWH as lamp is also the royal metaphor: 2 Sam 21:17 uses the lamp idiom for David himself ('you shall not go out with us to battle anymore, lest you quench the lamp of Israel'). The Davidic king is the lamp of Israel, and YHWH is the lamp of the Davidic king — a nested lamp-theology that the NT applies to Christ (John 8:12: 'I am the light of the world').</p>",
        "30": "<p>'For by you I can run against a troop, and by my God I can leap over a wall.' The military-prowess claims of vv30-46 are explicitly attributed to divine empowerment — not David's natural ability but YHWH's equipping. This is the inverse of the Deuteronomic warning against relying on military hardware (horses, chariots, numbers): David's victories come through YHWH's direct empowerment of the king. The theology of weakness-made-strong through divine empowerment (Paul: 'when I am weak, then I am strong,' 2 Cor 12:10) is deeply rooted in this warrior-king tradition.</p>",
        "31": "<p>'This God — his way is perfect; the word of YHWH proves true; he is a shield for all those who take refuge in him.' The theological summary of the entire poem: YHWH's way (<em>darKô tāmîm</em>) is perfect/blameless — the same word used of David in v24, now applied to God. The divine perfection grounds the human possibility of covenant faithfulness. His word (<em>ʾimraṯ YHWH ṣĕrûpâ</em>) is refined/tested — the refining-fire metaphor for tested purity. The word proves true through events: the poem is itself the proof-text that YHWH's word of covenant to David has been kept.</p>",
        "32": "<p>'For who is God, but YHWH? And who is a rock, except our God?' The rhetorical questions challenge the ANE divine plurality: in a world where every nation had its patron deity and the gods competed, the poem asserts YHWH's uniqueness. This monotheistic claim in the context of royal victory is politically charged: David's victories over surrounding nations (chs 8, 10) demonstrate that their patron deities cannot protect them. The rock imagery (used seven times in ch 22) frames YHWH as the most stable, permanent, reliable reality — the opposite of the shifting sands of human fortune.</p>",
        "33": "<p>'This God is my strong refuge and has made my way blameless.' YHWH as <em>māʿôz</em> (fortress/stronghold) recapitulates the opening epithet cluster. The claim that YHWH 'made my way blameless' is important: the poet's blamelessness (v24) is not a self-generated achievement but a gift. YHWH enables the covenant faithfulness that the psalm then claims — a grace-enabled righteousness, not a merit-righteousness. This is the same structure as Paul's 'work out your own salvation with fear and trembling, for it is God who works in you both to will and to work' (Phil 2:12-13).</p>",
        "34": "<p>'He made my feet like the feet of a deer and set me secure on the heights.' The deer-footed image — sure-footedness on mountain terrain — draws on the actual geography of David's military campaigns in the hill country of Judah and the eastern highlands. The feet of a deer (<em>ʾayyālôt</em>, female deer/doe) on rugged mountain terrain is the embodiment of confident agility in dangerous landscape. Habakkuk 3:19 uses the same image: 'God, the Lord, is my strength; he makes my feet like the deer's; he makes me tread on my high places.'</p>",
        "35": "<p>'He trains my hands for war, so that my arms can bend a bow of bronze.' The bow of bronze is the elite weapon of the period — a composite bow reinforced with metal for maximum draw weight and range. In the Iron Age Levant, the ability to draw a bronze-reinforced bow was a mark of elite warrior status. YHWH is credited with the physical training that produces this capacity. The theology is thoroughgoing: natural ability, physical training, and military success are all attributed to YHWH's equipping. There is no secular-sacred division in the poem's worldview.</p>",
        "36": "<p>'You have given me the shield of your salvation, and your gentleness made me great.' The word for gentleness here — <em>ʿanwâ</em> (humility, meekness) — is unexpected in a victory hymn. YHWH's greatness-making is achieved not through overwhelming force but through divine meekness/condescension. This is one of the most theologically loaded words in the psalm: the sovereign of the cosmos stoops down to make a fugitive shepherd-king great. It is the incarnational principle avant la lettre — the divine condescension that makes human greatness possible.</p>",
        "37": "<p>'You gave a wide place for my steps under me, and my feet did not slip.' The spacious-place (<em>rāḥaḇ</em>) imagery recapitulates v20. The stability of David's footsteps is the covenant security metaphor: YHWH secures the path so that the servant does not slip. Slipping (<em>māʿaḏ</em>) is used in the Psalter for covenant failure and the spiritual instability that precedes it (Ps 73:2: 'my feet had almost stumbled; my steps had nearly slipped'). The stability YHWH provides is both physical (in battle) and covenantal (in faithfulness).</p>",
        "38": "<p>'I pursued my enemies and destroyed them, and did not turn back until they were consumed.' The relentless pursuit and destruction of enemies is the ANE royal military formula — the language of the victory stele, the war annals of Egyptian and Assyrian kings. David adopts this genre entirely, but attributes the success to YHWH rather than to his own heroic prowess. This is the standard Hebrew war theology: the verb forms describe David's actions, but v33-36 have already established that every capacity was divinely given. The warrior acts; the victory belongs to YHWH.</p>",
        "39": "<p>'I consumed them; I thrust them through, so that they did not rise; they fell under my feet.' The complete subjugation language — enemies under the feet — is the standard ANE iconography of royal victory: the king placing his foot on the neck of the prostrate enemy (cf. Josh 10:24). In the royal theology of the Psalter, this image becomes the messianic template: 'Sit at my right hand until I make your enemies your footstool' (Ps 110:1), cited more often in the NT than any other OT text as the primary lens for understanding Christ's exaltation and cosmic rule.</p>",
        "40": "<p>'For you equipped me with strength for the battle; you made those who rise against me sink under me.' The divine equipping (<em>tĕʾazĕrēnî</em>) and the making-to-sink (<em>wayyikrĕʿû</em>) are both divine acts — the same pattern as Exodus: YHWH fights while Israel advances. The poem's theology of holy war is not that Israel fights for God but that God fights through Israel's obedient participation. When this equation breaks down (Achan at Ai; Saul at Amalek), defeat follows. David's victories confirm that the equation held — provisionally.</p>",
        "41": "<p>'You made my enemies turn their backs to me, those who hated me, and I destroyed them.' Turning the back is the shame-posture of the defeated in ANE warfare — to show one's back is to concede. The enemies' backs turned to David is the visual opposite of the enthroned king before whom conquered peoples prostrate themselves. The theological claim is that YHWH actively turned the enemies, not merely that David defeated them. The verb causative (<em>wayyitēn</em>) marks the action as divine, not human.</p>",
        "42": "<p>'They looked, but there was none to save; they cried to YHWH, but he did not answer them.' The enemies' unanswered cry to YHWH is a pointed inversion: the same cry David makes in v7 (and YHWH answers) the enemies also make in extremity, and YHWH is silent. The contrast maps onto the covenant distinction: YHWH hears those in covenant relationship with him; those who are his enemies in their conduct of life find that the same God who answered David does not answer them. This is not arbitrary — it reflects the covenant structure of the divine-human relationship.</p>",
        "43": "<p>'I beat them fine as the dust of the earth; I crushed them and stamped them down like the mire of the streets.' The crushing and stamping imagery is hyperbolic conquest language — the ANE war report idiom. Comparing defeated enemies to dust and street-mire reduces them to the lowest possible status in a culture where honor and shame were the primary social currency. The theological frame (this is YHWH's victory through David) prevents this from being mere triumphalism — it is the assertion that YHWH's enemies are ultimately brought to nothing.</p>",
        "44": "<p>'You delivered me from strife with my people; you kept me as the head of the nations; people whom I had not known served me.' The shift from foreign enemies to 'strife with my people' acknowledges the civil war with Saul's faction and later Absalom's rebellion. YHWH's preservation of David even through internal Israelite conflict is the most difficult deliverance — external enemies fight at the borders, but internal enemies threaten the covenant community itself. The nations serving David echoes the Abrahamic promise (Gen 12:3) and the Davidic covenant's expansion to include international rule.</p>",
        "45": "<p>'Foreigners came cringing to me; as soon as they heard of me, they obeyed me.' The tribute-bringing imagery and the voluntary submission of foreign nations to the Davidic king reflects the historical reality of David's imperial expansion (2 Sam 8: subjugation of Moab, Edom, Philistines, Ammonites, Arameans) and the ANE court protocol of subject peoples bringing tribute to the sovereign. In the royal theology, this submission prefigures the eschatological gathering of nations to the Davidic throne — a theme Isaiah (11:10; 42:6; 49:6) develops into the mission of the Servant to the nations.</p>",
        "46": "<p>'Foreigners lost heart and came trembling out of their fortresses.' The metaphor of coming trembling from fortresses — the strongest defensive position of the ancient world — captures the psalmist's point: even the most fortified position is no protection against YHWH's intervention on behalf of his king. The fortress imagery (YHWH as fortress in v2; enemies leaving their fortresses in submission in v46) forms a chiastic frame: the poem begins with the divine fortress protecting David and ends with human fortresses providing no protection for his enemies.</p>",
        "47": "<p>'YHWH lives! And blessed be my rock, and exalted be my God, the rock of my salvation.' The climactic doxology begins with <em>ḥay YHWH</em> — YHWH lives, is living, is the living God (as opposed to the silent, dead idols who could not answer their worshipers in v42). This is the confession of the resurrection life of God — the Psalter's equivalent of the NT's confession that the Father raised Jesus from the dead. The God who acts in history is the living God, not the static divine principle of Greek philosophy.</p>",
        "48": "<p>'The God who gave me vengeance and brought down peoples under me.' <em>Niqmôṯ</em> (vengeance/vindication) in OT theology is not primarily retributive emotion but covenant justice — YHWH's setting-right of covenant wrongs. When YHWH takes vengeance, he is acting as the covenant enforcer who holds people accountable for their treatment of his covenant partners. Deut 32:35 ('vengeance is mine') and Rom 12:19 (Paul quoting it) both insist that YHWH's vengeance is precisely what removes the need for human retaliation — he will act, so we need not.</p>",
        "49": "<p>'Who rescued me from my enemies; yes, you exalted me above those who rose against me; you delivered me from the man of violence.' The triple statement of rescue (enemies, those rising against, violent man) covers the spectrum of David's actual threats: Saul, Absalom, Sheba, foreign nations. The poem is deliberately comprehensive in its scope — YHWH's rescue spans the entire narrative arc of David's life as told in 1-2 Samuel. The placement of this psalm at the narrative's conclusion invites the reader to reread the entire David story through this interpretive lens.</p>",
        "50": "<p>'For this I will praise you, YHWH, among the nations, and sing to your name.' This verse is cited verbatim in Romans 15:9 — Paul's catena of OT texts proving that the Gentile mission was always YHWH's plan. 'I will praise you among the nations' places the Davidic king as the one through whose worship YHWH is glorified among non-Israelite peoples. Paul applies this to Christ: the son of David's praise among the nations is fulfilled in the proclamation of the gospel to all peoples, and Christ himself as the ultimate Davidic king leads this praise (Heb 2:12).</p>",
        "51": "<p>'Great salvation he brings to his king, and shows steadfast love to his anointed, to David and his offspring forever.' The closing verse of 2 Sam 22 / Ps 18 is the most concentrated theological statement in the book: <em>māšîaḥô</em> — his anointed one, his Messiah. The poem is the Messiah's own song, the covenant song of the anointed king. The <em>ḥesed</em> to David and his offspring forever is the Davidic covenant (2 Sam 7) in its most compressed form: the eternal covenant-loyalty (<em>ḥesed</em>) runs not just to David but to his seed — and in NT theology, that seed is Christ (Gal 3:16 applies the same seed-logic to the Abrahamic promise: 'to your offspring,' which is Christ).</p>"
    },
    "23": {
        "1": "<p>2 Samuel 23:1-7 is identified as 'the last words of David' — a formal literary genre in the ancient Near East known as the royal testament, in which a dying king delivers his final wisdom and theological testament to his successors. The form is attested in Mesopotamian royal literature and in the OT in Moses's final speeches (Deut 31-33), Jacob's deathbed blessings (Gen 49), and Joshua's farewell (Josh 23-24). David's 'last words' are composed as a poem — structured, elevated, using the language of prophecy (<em>nĕʾum</em>, oracle/utterance, the standard prophetic formula). The poem is his theology of kingship in concentrated form.</p>",
        "2": "<p>'The Spirit of YHWH speaks by me; his word is on my tongue.' David claims prophetic inspiration for these final words — the Spirit of YHWH as the source of the speech. This is the same claim made by OT prophets (<em>kōh ʾāmar YHWH</em>, thus says YHWH) and developed in the NT understanding of Scripture as God-breathed (<em>theopneustos</em>, 2 Tim 3:16). David as king-prophet is a figure in the development of the messianic expectation: the Messiah is prophet, priest, and king, and David's anointing with the Spirit for both military leadership and prophetic speech anticipates this triple office.</p>",
        "3": "<p>'The God of Israel has spoken; the Rock of Israel has said to me: When one rules justly over men, ruling in the fear of God.' The ideal king of v3-4 — ruling with justice and in the fear of God — is the Deuteronomic royal ideal (Deut 17:18-20) and the messianic expectation that drives Isaiah's vision of the branch from David's root (Isa 11:1-5: 'the Spirit of the LORD shall rest upon him ... he shall judge with righteousness'). David is pointing beyond himself to a king who fulfills what he himself only partially embodied. The Last Words are intentionally messianic in their orientation.</p>",
        "4": "<p>'He dawns on them like the morning light, like the sun shining forth on a cloudless morning, like rain that makes grass sprout from the earth.' The triple simile of the just king — morning light, cloudless sunrise, rain on grass — draws on the universal experience of agricultural peoples: light enables sight and growth; rain gives life to the land. The king as solar figure has ANE antecedents (Egyptian pharaoh as sun-god; Assyrian kings in solar iconography), but the poem demythologizes it: the king is not the sun but like the sun, not the source of life but the vehicle through which YHWH's life-giving governance reaches the people. Malachi 4:2 will call the Messiah the 'sun of righteousness.'</p>",
        "5": "<p>'For does not my house stand so with God? For he has made with me an everlasting covenant, ordered in all things and secure. For will he not cause to prosper all my help and my desire?' The everlasting covenant (<em>bĕrîṯ ʿôlām</em>) anchoring David's confidence is the Davidic covenant of 2 Sam 7. <em>Bĕrîṯ ʿôlām</em> is the deepest category of covenant in OT theology — used also of the Noahic covenant (Gen 9:16), the Abrahamic covenant (Gen 17:7), and the priestly covenant (Num 25:13). Its eternality distinguishes it from conditional covenants that can be broken. Hebrews 13:20 applies <em>bĕrîṯ ʿôlām</em> to Christ's resurrection: he was raised by 'the blood of the eternal covenant.'</p>",
        "6": "<p>'But worthless men are all like thorns that are thrust away, for they cannot be taken with the hand.' The contrast between the just king and the worthless men (<em>bĕliyyaʿal</em>, the same term used for the forces of chaos in v22:5) sets up a sharp binary: the kingdom of the just king flourishes; those who embody anti-covenantal disorder cannot be grasped but must be driven away. The thorn imagery — thorns cannot be held, only thrust away with iron and wood — foreshadows the crown-of-thorns irony of the Passion: the just king wears the symbols of the worthless disorder he came to overcome.</p>",
        "7": "<p>'They are not taken with the hand; the man who touches them arms himself with iron and the handle of a spear, and they are utterly consumed with fire in their place.' The consuming fire of worthless men echoes the theophanic fire of ch 22 turned now to judgment of the ungodly. The fire that protected the just king (22:9) destroys the worthless (<em>bĕliyyaʿal</em>) ones. This binary — protective fire and consuming fire as the same divine reality experienced differently — runs through OT theology and is systematized in Hebrews 12:29: 'our God is a consuming fire.' The covenant promise is simultaneously protective and judicial.</p>",
        "8": "<p>2 Samuel 23:8-39 lists the <em>gibbôrîm</em> (mighty men/warriors) of David — his elite military retinue. The warrior-band of the ancient Near East was a distinct social institution: a group of elite fighters who bound themselves in personal loyalty to a patron-king, receiving land and honor in return for military service. David's gibbôrîm originated in the Adullam band (1 Sam 22:2: 400 distressed, indebted, bitter men who gathered to David the outlaw) and developed into a professional elite corps. The list is a historical document of early monarchic Israel's military organization, preserving personal names, home villages, and specific acts of valor.</p>",
        "9": "<p>Eleazar son of Dodo the Ahohite — one of the Three. His exploit: standing alone against the Philistines 'until his hand was weary and his hand clung to the sword' (v10). The individual valor accounts in the gibbôrîm list follow a standard ANE hero-account format: name/patronymic/clan, specific exploit, result. The result statement often includes a communal note — 'the people came after him only to strip the slain' — which emphasizes the disproportionate contribution of the hero relative to the rest. These accounts preserved oral traditions of specific battles before they were integrated into the court archives.</p>",
        "10": "<p>'He stood his ground and struck down the Philistines until his hand was weary and his hand clung to the sword. And YHWH brought about a great victory that day, and the troops came back after him only to strip the slain.' The theological refrain — 'YHWH brought about a great victory' — appears after individual exploits (v10, 12) to prevent the accounts from becoming pure hero-cult. The gibbôrîm's valor is real and celebrated; but the victory belongs to YHWH. This is the consistent theology of the Samuel narratives: human courage is genuine, divine agency is primary.</p>",
        "11": "<p>Shammah son of Agee the Hararite — his exploit: defending a plot of lentils while the Israelite troops fled. The domesticity of the detail — a lentil field, not a strategic location — is characteristic of authentic oral tradition. Court-generated heroic epics would choose more glorious settings. The preservation of a lentil-field defense suggests this is a genuine eyewitness account or very early oral tradition about an otherwise obscure skirmish. The theological refrain repeats: 'YHWH brought about a great victory.'</p>",
        "12": "<p>'But he took his stand in the midst of the plot and defended it and struck down the Philistines, and YHWH worked a great victory.' The parallel structure of v10 and v12 — same exploit-and-divine-victory formula for both Eleazar and Shammah — marks them as a recognized pair within the Three. The gibbôrîm traditions seem to have circulated in pairs and groups before being assembled into the full list. The dual framing emphasizes that two different men, in two different places, embodied the same combination of personal courage and divine empowerment.</p>",
        "13": "<p>'And three of the thirty chief men went down and came about harvest time to David at the cave of Adullam, when a band of Philistines was encamped in the Valley of Rephaim.' The Bethlehem water incident (vv13-17) is one of the most theologically rich episodes in the gibbôrîm accounts. Its placement — during the period when David was at Adullam and the Philistines held Bethlehem — situates it in the early outlaw period, before the kingship. The Valley of Rephaim west of Jerusalem was a frequent Philistine invasion route into the Judean highlands.</p>",
        "14": "<p>'David was then in the stronghold, and the garrison of the Philistines was then at Bethlehem.' The topography is precise: David in the hill-fortress caves, Philistines occupying his hometown. The homesickness that drives v15 is rooted in the concrete geography of exile from one's birthplace under enemy occupation. Bethlehem — the town of David's origin, where Samuel anointed him — is now occupied territory. The longing for Bethlehem water is inseparable from the longing to return to the place of divine election and covenant origin.</p>",
        "15": "<p>'And David said longingly, Oh, that someone would give me water to drink from the well of Bethlehem that is by the gate!' The word for longing (<em>yiṯʾawwēh</em>) describes intense craving — the same root used for the craving of the wilderness generation for food (Num 11:4, <em>hiṯʾawwû taʾăwâ</em>). David's longing is not strategically disguised as a military order — it is a moment of exposed, vulnerable homesickness. The three men who hear it act on the longing without being commanded to do so. Their response is pure covenant loyalty (<em>hesed</em>) — acting on the unspoken need of their king.</p>",
        "16": "<p>'Then the three mighty men broke through the camp of the Philistines and drew water out of the well of Bethlehem that was by the gate and carried and brought it to David.' The three warriors breach Philistine lines — a military operation — to bring water from a specific well. The water is not strategically necessary; it is deeply personal. Their willingness to risk their lives for what amounts to a gesture of devotion to their king is the <em>hesed</em> ideal enacted in blood-risking loyalty. David's response — pouring the water out as a libation — is the theological recognition that such blood-cost service belongs to God, not to human consumption.</p>",
        "17": "<p>'He would not drink it. He poured it out to YHWH and said, Far be it from me, YHWH, that I should do this. Shall I drink the blood of the men who went at the risk of their lives? Therefore he would not drink it. These things the three mighty men did.' David's refusal to drink the water and his pouring it as a libation (<em>wayyassĕkēhā lYHWH</em>) is one of the most theologically charged acts in the Samuel narrative. Water obtained at the cost of men's lives becomes blood — and David will not consume blood (Lev 17:10-14; Deut 12:23). But more profoundly: he elevates their costly service to the category of sacrifice. What costs human life is too sacred for private consumption — it belongs to YHWH. Philippians 2:17 ('even if I am being poured out as a drink offering over the sacrifice and service of your faith') uses the same libation imagery for self-giving ministry.</p>",
        "18": "<p>Abishai the brother of Joab, son of Zeruiah, chief of the Thirty. Abishai appears throughout the David narrative as the most loyal of the Zeruiah brothers — the one who offers to behead Shimei (2 Sam 16:9), who rescues David from the Philistine giant (2 Sam 21:17), who defeats Edom in the Valley of Salt (1 Chr 18:12). He is placed first among the Thirty (or the Three, textual variant) because of his distinction, though he is not counted among the Three proper. The family loyalty of the Zeruiah brothers — Joab, Abishai, Asahel — is a recurring theme in the David narrative, sometimes protective and sometimes problematic.</p>",
        "19": "<p>'He was the most renowned of the thirty and became their commander, but he did not attain to the three.' The ranking system within the gibbôrîm — the Three above the Thirty — reflects the Iron Age Israelite military organization. The gibbôrîm were likely a standing professional corps distinct from the tribal levy. The Three appear to have been the highest-honor category, perhaps based on specific outstanding exploits that earned them permanent recognition. Abishai's distinction — most honored of the Thirty but not reaching the Three — is preserved with careful precision, suggesting these rankings were matters of institutional record.</p>",
        "20": "<p>Benaiah son of Jehoiada — his exploits include killing two Ariel/lion-men of Moab, killing a lion in a pit on a snowy day, and killing an Egyptian warrior with his own spear. The Benaiah accounts are among the most vivid individual hero-narratives in the list. The pit/snow/lion exploit in particular has the specificity of authentic tradition: the snowy day, the pit, the lion — details that serve no rhetorical purpose except accurate preservation. Benaiah will become Solomon's chief of the royal guard (1 Kings 2:35), suggesting these accounts were preserved in the court to explain the careers of prominent officials.</p>",
        "21": "<p>'He also went down and struck down a lion in a pit on a snowy day. He struck down an Egyptian, a handsome man. The Egyptian had a spear in his hand, but Benaiah went down to him with a staff and snatched the spear out of the Egyptian's hand and killed him with his own spear.' The asymmetric weapon exploit — staff against spear, ending with the opponent's own weapon used against him — is a specific type of hero-narrative in ANE literature that demonstrates not just courage but tactical intelligence. Benaiah does not simply overpower a superior weapon with brute strength; he maneuvers to take control of the weapon. This earns him a place among the most honored warriors.</p>",
        "22": "<p>'These things Benaiah son of Jehoiada did, and won a name beside the three mighty men.' Benaiah's fame is ranked beside the Three though not among them — the same formula used of Abishai (v19). The careful ranking distinctions preserved in the list reflect the pride of the gibbôrîm as an institution: their distinctions mattered, and the historical record preserved them. The list as a whole is a monument to the men who made the Davidic kingdom possible — not a king-centered glorification but a community of named individuals whose specific acts of valor built something larger than themselves.</p>",
        "23": "<p>'He was renowned among the thirty, but he did not attain to the three. And David set him over his bodyguard.' Benaiah's administrative role — commander of the bodyguard — is the institutional consequence of his personal valor and proximity to the king. The king's bodyguard in the ancient world were the most trusted personal retainers, responsible for the king's physical safety. Benaiah's posting there explains why he appears at critical moments in the succession narrative: he is the one who executes Joab and Shimei on Solomon's orders (1 Kings 2), precisely because his loyalty is to the Davidic throne rather than to any faction.</p>",
        "24": "<p>The list of the Thirty (vv24-39) begins with Asahel brother of Joab — the fleet-footed warrior killed by Abner at the beginning of the civil war (2 Sam 2:18-23). His inclusion at the head of the Thirty despite his early death suggests the list preserves a historical roster from a specific point in David's reign, not a snapshot of his final military establishment. The list spans the entire range of Israelite and Judahite geography, suggesting a deliberate effort to represent multiple tribal territories in the elite corps — a political as well as military construction.</p>",
        "25": "<p>The geographic range of the Thirty — Bethlehem (Elhanan son of Dodo), the Harod valley (Shammah the Harodite, Elika the Harodite), Tekoa (Ira son of Ikkesh), Gibeah (Abiezer the Anathothite), Hushah (Sibbecai), Anathoth (Abiezer) — reflects the pan-Israelite character of David's military establishment. The Thirty are not drawn exclusively from Judah (David's own tribe) but from across the northern and central highlands. This breadth suggests a deliberate effort to build a coalition force whose loyalty was to the king personally rather than to tribal faction.</p>",
        "26": "<p>Heleb son of Baanah the Netophathite, Ittai son of Ribai of Gibeah of the Benjaminites — the Benjaminite presence in the Thirty is politically significant. Benjamin was Saul's tribe, and Saul's family and loyalists regarded David with hostility (Shimei's cursing in 2 Sam 16 reflects this). The inclusion of Benjaminite warriors in David's elite corps reflects successful covenant-building across the tribal divide that the civil war had opened. The Thirty are a peace-building institution as well as a military one.</p>",
        "27": "<p>Abiezer the Anathothite — Anathoth is the village that will produce Jeremiah (Jer 1:1). The gibbôrîm list thus preserves the geographic and social world from which later prophetic figures emerged. The village communities that supplied warriors to David's elite corps were the same communities whose sons became prophets generations later. The list is not merely military history — it is a window into the social world of early Israel's communities and their relationship to the monarchy.</p>",
        "28": "<p>Zalmon the Ahohite — the Ahohite clan appears twice in the list (Dodo the Ahohite in v9 as the father of Eleazar, one of the Three). The preservation of clan identifiers throughout the list suggests that the gibbôrîm had a hereditary or at least clan-based character: valor ran in families, and the elite corps maintained family-based traditions of loyalty to the Davidic throne. This clan loyalty dynamic is part of what made the institution so stable across generations.</p>",
        "29": "<p>Heleb of Carmel, Paarai the Arbite — Carmel (not to be confused with Mount Carmel) is a town in the Judean hill country near Hebron, where Nabal the churl grazed his flocks and Abigail acted with wisdom (1 Sam 25). The gibbôrîm list thus intersects with the narrative of David's early Judean connections — the men of Carmel knew David from the wilderness period when he was a protecting warlord before he was king. The Thirty represent the maturation of those earlier personal loyalties into institutional military service.</p>",
        "30": "<p>Hiddai of the brooks of Gaash, Abialbon the Arbathite — the brooks of Gaash are in the Ephraim hill country, the same region where Joshua was buried (Josh 24:30). The geographic range now extends into Ephraim, the dominant northern tribe. The inclusion of Ephraimite warriors reflects David's successful integration of northern tribal loyalties into the Davidic military establishment — the foundation for his brief pan-Israelite kingdom before Rehoboam's failure destroyed it.</p>",
        "31": "<p>Azmaveth the Barhumite, Eliahba the Shaalbonite — the Shaalbonites are associated with the Dan/Naphtali area in the far north. The gibbôrîm thus span from Bethlehem in the south to the northern highlands — a geographic range that mirrors the territorial ambition of the Davidic state. These were not merely Judahite warriors defending Judean interests; they were warriors from across the entire Israelite territory who personally committed to the Davidic royal house.</p>",
        "32": "<p>Jonathan son of Shammah the Hararite — the Hararites appear twice (Shammah in v11 as the one who defended the lentil field, now his son Jonathan in the Thirty). The father-son dynastic succession within the gibbôrîm list confirms the hereditary character of the institution. Elite warrior status passed from father to son, building multi-generational loyalty networks around the Davidic throne. This is the social infrastructure of dynastic monarchy — not just political power but networks of personal obligation and family honor.</p>",
        "33": "<p>Ahiam son of Sharar the Hararite — another Hararite warrior, suggesting a clan or village with a strong tradition of military service to David. The repetition of geographic identifiers (Hararite appears three times in the list) indicates that certain communities produced warriors for the elite corps across generations. These were the equivalent of the military families that have served specific armies or royal houses across centuries in world history.</p>",
        "34": "<p>Eliphelet son of Ahasbai of Maacah — Maacah is an Aramean kingdom in the area of the upper Jordan valley/Golan. The inclusion of a man identified with a foreign kingdom in the Thirty reflects the international character of David's military corps. David's gibbôrîm included Hittites (Uriah), Cherethites, Pelethites (Philistine mercenaries), and Aramean-affiliated warriors. The Thirty is a remarkable ethnic coalition — the most internationally diverse military institution in the pre-exilic period.</p>",
        "35": "<p>Eliam son of Ahithophel the Gilonite — this is a stunning identification. Ahithophel the Gilonite was David's closest counselor, whose advice was like 'the word of God' (2 Sam 16:23), who defected to Absalom, gave perfect military counsel that Hushai thwarted, and hanged himself when his counsel was rejected (17:23). Eliam his son is listed here as one of the Thirty — a warrior loyal to David. And in 2 Sam 11:3, Bathsheba is identified as the daughter of Eliam. If this identification is correct (and it is widely accepted by scholars), then Ahithophel was Bathsheba's grandfather, and David's seizure of Bathsheba was a personal violation against his most trusted counselor's family — which gives Ahithophel's defection to Absalom a deeply personal motive that the narrative never makes explicit but the genealogy implies.</p>",
        "36": "<p>Hezo the Carmelite, Paarai the Arbite — the list continues through warriors from Judean towns, each name preserving a human being whose identity would otherwise be lost. The theological significance of the names-list is the same as the genealogies: the covenant community is made of particular people in particular places, not an abstract collective. YHWH's faithfulness to his covenant runs through specific named individuals — which is why biblical genealogies and name-lists are not dispensable filler but constitute part of the theological argument about how covenant history works.</p>",
        "37": "<p>Igal son of Nathan from Zobah, Bani the Gadite — Zobah is the Aramean kingdom north of Damascus that David defeated (2 Sam 8:3-8). A warrior 'from Zobah' in the Thirty is another evidence of the international character of David's forces: conquered enemies sometimes became loyal servants in the Davidic military establishment. This is the ANE pattern of military incorporation — defeated warriors offered the option of service to the conqueror — but the gibbôrîm list suggests some achieved genuine distinction and honor.</p>",
        "38": "<p>Zelek the Ammonite, Naharai the Beerothite, the armor-bearer of Joab son of Zeruiah — an Ammonite warrior in David's Thirty is remarkable given that the Ammonite war of 2 Samuel 10-12 was the context for David's sin with Bathsheba and the murder of Uriah. Ammonite warriors serve in David's elite corps even as David is waging war against Ammon. The complexity of the military world is preserved here without editorial smoothing: the political conflict between nations did not prevent individual Ammonites from finding honorable service in the Davidic military establishment.</p>",
        "39": "<p>'Uriah the Hittite — thirty-seven in all.' The list ends with Uriah the Hittite — the man whose murder David engineered (2 Sam 11). The placement is devastating in its simplicity: Uriah is listed among the greatest warriors who served David loyally. He had carried Joab's letter ordering his own death-exposure without opening it, because he trusted his king. His name appears last on the roll of honor, ensuring that the canonical narrative preserves him not as a victim-footnote but as a named, honored member of the community of the faithful. The list's final word — 'thirty-seven in all' — counts Uriah among David's greatest men. The editors knew exactly what they were doing.</p>"
    }
}


def main():
    existing = load_comm('mkt-context', '2samuel')
    merge_comm(existing, SAMUEL2_CONTEXT_CH22_23)
    save_comm('mkt-context', '2samuel', existing)

    ch22 = existing.get('22', {})
    ch23 = existing.get('23', {})
    print(f'ch 22: {len(ch22)} verse entries')
    print(f'ch 23: {len(ch23)} verse entries')

    # completeness check
    interlinear_path = ROOT / 'data' / 'interlinear' / '2samuel.json'
    if interlinear_path.exists():
        il = json.loads(interlinear_path.read_text())
        for ch_num in ['22', '23']:
            il_verses = set(il.get(ch_num, {}).keys())
            comm_verses = set(existing.get(ch_num, {}).keys())
            missing = il_verses - comm_verses
            if missing:
                print(f'  ch {ch_num} missing: {sorted(missing, key=int)}')
            else:
                print(f'  ch {ch_num}: complete ({len(comm_verses)}/{len(il_verses)} verses)')


if __name__ == '__main__':
    main()
